     1→<!DOCTYPE html>
     2→<html lang="zh">
     3→<head>
     4→<meta charset="UTF-8">
     5→<meta name="viewport" content="width=device-width, initial-scale=1.0">
     6→<title>Kiro Memory</title>
     7→<style>
     8→  * { box-sizing: border-box; margin: 0; padding: 0; }
     9→
    10→  :root {
    11→    --bg: #0f1117;
    12→    --surface: #1a1d27;
    13→    --surface2: #22263a;
    14→    --border: #2e3250;
    15→    --accent: #6c8ef5;
    16→    --accent2: #a78bfa;
    17→    --text: #e2e8f0;
    18→    --text-muted: #8892b0;
    19→    --user-bg: #1e2d4a;
    20→    --assistant-bg: #1a2235;
    21→    --tag-bg: #2a3060;
    22→    --green: #4ade80;
    23→    --yellow: #fbbf24;
    24→  }
    25→
    26→  body {
    27→    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif;
    28→    background: var(--bg);
    29→    color: var(--text);
    30→    height: 100vh;
    31→    display: flex;
    32→    flex-direction: column;
    33→    overflow: hidden;
    34→  }
    35→
    36→  /* ── Header ── */
    37→  header {
    38→    display: flex;
    39→    align-items: center;
    40→    gap: 12px;
    41→    padding: 14px 24px;
    42→    background: var(--surface);
    43→    border-bottom: 1px solid var(--border);
    44→    flex-shrink: 0;
    45→  }
    46→  header .logo {
    47→    width: 28px; height: 28px;
    48→    background: linear-gradient(135deg, var(--accent), var(--accent2));
    49→    border-radius: 8px;
    50→    display: flex; align-items: center; justify-content: center;
    51→    font-size: 14px; font-weight: 700; color: #fff;
    52→  }
    53→  header h1 { font-size: 16px; font-weight: 600; color: var(--text); }
    54→  header .subtitle { font-size: 12px; color: var(--text-muted); margin-left: auto; }
    55→
    56→  /* ── Tabs ── */
    57→  .tabs {
    58→    display: flex;
    59→    gap: 4px;
    60→    padding: 12px 24px 0;
    61→    background: var(--surface);
    62→    border-bottom: 1px solid var(--border);
    63→    flex-shrink: 0;
    64→  }
    65→  .tab {
    66→    padding: 8px 18px;
    67→    border-radius: 8px 8px 0 0;
    68→    cursor: pointer;
    69→    font-size: 13px;
    70→    font-weight: 500;
    71→    color: var(--text-muted);
    72→    border: 1px solid transparent;
    73→    border-bottom: none;
    74→    transition: all .15s;
    75→  }
    76→  .tab:hover { color: var(--text); background: var(--surface2); }
    77→  .tab.active {
    78→    color: var(--accent);
    79→    background: var(--bg);
    80→    border-color: var(--border);
    81→    border-bottom-color: var(--bg);
    82→  }
    83→
    84→  /* ── Main layout ── */
    85→  .main {
    86→    display: flex;
    87→    flex: 1;
    88→    overflow: hidden;
    89→  }
    90→
    91→  /* ── Panel ── */
    92→  .panel { display: none; width: 100%; overflow: hidden; }
    93→  .panel.active { display: flex; }
    94→
    95→  /* ── Memory Panel ── */
    96→  #panel-memory {
    97→    flex-direction: row;
    98→  }
    99→  .memory-sidebar {
   100→    width: 220px;
   101→    flex-shrink: 0;
   102→    border-right: 1px solid var(--border);
   103→    overflow-y: auto;
   104→    padding: 12px 8px;
   105→    background: var(--surface);
   106→  }
   107→  .memory-sidebar h3 {
   108→    font-size: 11px;
   109→    text-transform: uppercase;
   110→    letter-spacing: .08em;
   111→    color: var(--text-muted);
   112→    padding: 4px 8px 8px;
   113→  }
   114→  .sidebar-section-label {
   115→    font-size: 10px;
   116→    text-transform: uppercase;
   117→    letter-spacing: .1em;
   118→    color: var(--text-muted);
   119→    padding: 12px 10px 4px;
   120→    opacity: 0.6;
   121→  }
   122→  .file-item .fsource {
   123→    font-size: 10px;
   124→    padding: 1px 5px;
   125→    border-radius: 8px;
   126→    background: var(--tag-bg);
   127→    color: var(--accent2);
   128→    display: inline-block;
   129→    margin-top: 2px;
   130→  }
   131→  .file-item {
   132→    padding: 8px 10px;
   133→    border-radius: 6px;
   134→    cursor: pointer;
   135→    font-size: 13px;
   136→    color: var(--text-muted);
   137→    transition: all .15s;
   138→    display: flex;
   139→    flex-direction: column;
   140→    gap: 2px;
   141→  }
   142→  .file-item:hover { background: var(--surface2); color: var(--text); }
   143→  .file-item.active { background: var(--tag-bg); color: var(--accent); }
   144→  .file-item .fname { font-weight: 500; }
   145→  .file-item .fdate { font-size: 11px; color: var(--text-muted); }
   146→
   147→  .memory-content {
   148→    flex: 1;
   149→    overflow-y: auto;
   150→    padding: 28px 36px;
   151→  }
   152→  .memory-content h2 {
   153→    font-size: 18px;
   154→    font-weight: 600;
   155→    margin-bottom: 20px;
   156→    color: var(--text);
   157→    display: flex;
   158→    align-items: center;
   159→    gap: 8px;
   160→  }
   161→  .memory-content h2 .badge {
   162→    font-size: 11px;
   163→    background: var(--tag-bg);
   164→    color: var(--accent);
   165→    padding: 2px 8px;
   166→    border-radius: 20px;
   167→    font-weight: 500;
   168→  }
   169→
   170→  /* ── History Panel ── */
   171→  #panel-history {
   172→    flex-direction: row;
   173→  }
   174→  .history-sidebar {
   175→    width: 280px;
   176→    flex-shrink: 0;
   177→    border-right: 1px solid var(--border);
   178→    overflow-y: auto;
   179→    background: var(--surface);
   180→  }
   181→  .history-sidebar h3 {
   182→    font-size: 11px;
   183→    text-transform: uppercase;
   184→    letter-spacing: .08em;
   185→    color: var(--text-muted);
   186→    padding: 16px 16px 8px;
   187→  }
   188→  .session-item {
   189→    padding: 12px 16px;
   190→    border-bottom: 1px solid var(--border);
   191→    cursor: pointer;
   192→    transition: background .15s;
   193→  }
   194→  .session-item:hover { background: var(--surface2); }
   195→  .session-item.active { background: var(--tag-bg); border-left: 3px solid var(--accent); }
   196→  .session-item .s-date {
   197→    font-size: 11px;
   198→    color: var(--text-muted);
   199→    margin-bottom: 4px;
   200→  }
   201→  .session-item .s-preview {
   202→    font-size: 13px;
   203→    color: var(--text);
   204→    line-height: 1.4;
   205→    display: -webkit-box;
   206→    -webkit-line-clamp: 2;
   207→    -webkit-box-orient: vertical;
   208→    overflow: hidden;
   209→  }
   210→
   211→  .conversation-view {
   212→    flex: 1;
   213→    overflow-y: auto;
   214→    padding: 24px 32px;
   215→    display: flex;
   216→    flex-direction: column;
   217→    gap: 24px;
   218→  }
   219→  .empty-state {
   220→    display: flex;
   221→    flex-direction: column;
   222→    align-items: center;
   223→    justify-content: center;
   224→    height: 100%;
   225→    color: var(--text-muted);
   226→    gap: 12px;
   227→  }
   228→  .empty-state .icon { font-size: 40px; }
   229→  .empty-state p { font-size: 14px; }
   230→
   231→  /* ── Round card ── */
   232→  .round-card {
   233→    background: var(--surface);
   234→    border: 1px solid var(--border);
   235→    border-radius: 12px;
   236→    overflow: hidden;
   237→  }
   238→  .round-header {
   239→    display: flex;
   240→    align-items: center;
   241→    gap: 8px;
   242→    padding: 10px 16px;
   243→    background: var(--surface2);
   244→    border-bottom: 1px solid var(--border);
   245→    font-size: 12px;
   246→    color: var(--text-muted);
   247→    cursor: pointer;
   248→    user-select: none;
   249→  }
   250→  .round-header .round-num {
   251→    background: var(--tag-bg);
   252→    color: var(--accent);
   253→    padding: 1px 7px;
   254→    border-radius: 10px;
   255→    font-size: 11px;
   256→    font-weight: 600;
   257→  }
   258→  .round-header .chevron {
   259→    margin-left: auto;
   260→    transition: transform .2s;
   261→  }
   262→  .round-header.collapsed .chevron { transform: rotate(-90deg); }
   263→
   264→  .round-body { padding: 0; }
   265→  .round-body.hidden { display: none; }
   266→
   267→  .msg-user, .msg-assistant {
   268→    padding: 16px 20px;
   269→  }
   270→  .msg-user {
   271→    background: var(--user-bg);
   272→    border-bottom: 1px solid var(--border);
   273→  }
   274→  .msg-assistant {
   275→    background: var(--assistant-bg);
   276→  }
   277→  .msg-label {
   278→    font-size: 11px;
   279→    font-weight: 600;
   280→    text-transform: uppercase;
   281→    letter-spacing: .06em;
   282→    margin-bottom: 8px;
   283→    display: flex;
   284→    align-items: center;
   285→    gap: 6px;
   286→  }
   287→  .msg-user .msg-label { color: var(--yellow); }
   288→  .msg-assistant .msg-label { color: var(--accent); }
   289→  .msg-dot {
   290→    width: 6px; height: 6px;
   291→    border-radius: 50%;
   292→    background: currentColor;
   293→  }
   294→  .msg-text {
   295→    font-size: 14px;
   296→    line-height: 1.7;
   297→    color: var(--text);
   298→    white-space: pre-wrap;
   299→    word-break: break-word;
   300→  }
   301→
   302→  /* ── Markdown rendering ── */
   303→  .md-content { font-size: 14px; line-height: 1.75; color: var(--text); }
   304→  .md-content h1 { font-size: 20px; font-weight: 700; margin: 20px 0 12px; color: var(--text); }
   305→  .md-content h2 { font-size: 17px; font-weight: 600; margin: 18px 0 10px; color: var(--text); border-bottom: 1px solid var(--border); padding-bottom: 6px; }
   306→  .md-content h3 { font-size: 15px; font-weight: 600; margin: 14px 0 8px; color: var(--accent2); }
   307→  .md-content p { margin-bottom: 10px; }
   308→  .md-content ul, .md-content ol { padding-left: 20px; margin-bottom: 10px; }
   309→  .md-content li { margin-bottom: 4px; }
   310→  .md-content code {
   311→    background: var(--surface2);
   312→    border: 1px solid var(--border);
   313→    padding: 1px 5px;
   314→    border-radius: 4px;
   315→    font-family: "JetBrains Mono", "Fira Code", monospace;
   316→    font-size: 12px;
   317→    color: var(--accent2);
   318→  }
   319→  .md-content pre {
   320→    background: #0d1117;
   321→    border: 1px solid var(--border);
   322→    border-radius: 8px;
   323→    padding: 14px 16px;
   324→    overflow-x: auto;
   325→    margin: 12px 0;
   326→  }
   327→  .md-content pre code {
   328→    background: none;
   329→    border: none;
   330→    padding: 0;
   331→    color: #c9d1d9;
   332→    font-size: 13px;
   333→  }
   334→  .md-content table {
   335→    width: 100%;
   336→    border-collapse: collapse;
   337→    margin: 12px 0;
   338→    font-size: 13px;
   339→  }
   340→  .md-content th {
   341→    background: var(--surface2);
   342→    padding: 8px 12px;
   343→    text-align: left;
   344→    border: 1px solid var(--border);
   345→    color: var(--accent);
   346→    font-weight: 600;
   347→  }
   348→  .md-content td {
   349→    padding: 7px 12px;
   350→    border: 1px solid var(--border);
   351→  }
   352→  .md-content tr:nth-child(even) td { background: var(--surface2); }
   353→  .md-content blockquote {
   354→    border-left: 3px solid var(--accent);
   355→    padding: 8px 16px;
   356→    margin: 10px 0;
   357→    background: var(--surface2);
   358→    border-radius: 0 6px 6px 0;
   359→    color: var(--text-muted);
   360→  }
   361→  .md-content strong { color: var(--text); font-weight: 600; }
   362→  .md-content a { color: var(--accent); text-decoration: none; }
   363→  .md-content a:hover { text-decoration: underline; }
   364→
   365→  /* ── Loading ── */
   366→  .loading {
   367→    display: flex;
   368→    align-items: center;
   369→    justify-content: center;
   370→    padding: 40px;
   371→    color: var(--text-muted);
   372→    font-size: 14px;
   373→    gap: 10px;
   374→  }
   375→  .spinner {
   376→    width: 18px; height: 18px;
   377→    border: 2px solid var(--border);
   378→    border-top-color: var(--accent);
   379→    border-radius: 50%;
   380→    animation: spin .7s linear infinite;
   381→  }
   382→  @keyframes spin { to { transform: rotate(360deg); } }
   383→
   384→  /* ── Scrollbar ── */
   385→  ::-webkit-scrollbar { width: 6px; }
   386→  ::-webkit-scrollbar-track { background: transparent; }
   387→  ::-webkit-scrollbar-thumb { background: var(--border); border-radius: 3px; }
   388→  ::-webkit-scrollbar-thumb:hover { background: var(--text-muted); }
   389→</style>
   390→</head>
   391→<body>
   392→
   393→<header>
   394→  <div class="logo">K</div>
   395→  <h1>Kiro Memory</h1>
   396→  <span class="subtitle">记忆 & 对话回溯</span>
   397→</header>
   398→
   399→<div class="tabs">
   400→  <div class="tab active" data-tab="memory">记忆文件</div>
   401→  <div class="tab" data-tab="history">对话历史</div>
   402→</div>
   403→
   404→<div class="main">
   405→
   406→  <!-- Memory Panel -->
   407→  <div id="panel-memory" class="panel active">
   408→    <div class="memory-sidebar">
   409→      <h3>文件列表</h3>
   410→      <div class="sidebar-section-label">📌 记忆</div>
   411→      <div id="file-list"><div class="loading"><div class="spinner"></div></div></div>
   412→      <div class="sidebar-section-label">📋 设计文档</div>
   413→      <div id="plan-list"><div class="loading"><div class="spinner"></div></div></div>
   414→    </div>
   415→    <div class="memory-content">
   416→      <div id="memory-display" class="empty-state">
   417→        <div class="icon">📂</div>
   418→        <p>选择左侧文件查看内容</p>
   419→      </div>
   420→    </div>
   421→  </div>
   422→
   423→  <!-- History Panel -->
   424→  <div id="panel-history" class="panel">
   425→    <div class="history-sidebar">
   426→      <h3>会话列表</h3>
   427→      <div id="session-list"><div class="loading"><div class="spinner"></div></div></div>
   428→    </div>
   429→    <div class="conversation-view" id="conversation-view">
   430→      <div class="empty-state">
   431→        <div class="icon">💬</div>
   432→        <p>选择左侧会话查看对话</p>
   433→      </div>
   434→    </div>
   435→  </div>
   436→
   437→</div>
   438→
   439→<script>
   440→let memoryFiles = [];
   441→let planFiles = [];
   442→let sessions = [];
   443→let activeFile = null;
   444→let activePlan = null;
   445→let activeSession = null;
   446→
   447→// ── Tab switching ──
   448→document.querySelectorAll('.tab').forEach(tab => {
   449→  tab.addEventListener('click', () => {
   450→    document.querySelectorAll('.tab').forEach(t => t.classList.remove('active'));
   451→    document.querySelectorAll('.panel').forEach(p => p.classList.remove('active'));
   452→    tab.classList.add('active');
   453→    document.getElementById('panel-' + tab.dataset.tab).classList.add('active');
   454→  });
   455→});
   456→
   457→// ── Memory ──
   458→async function loadMemory() {
   459→  const res = await fetch('/api/memory');
   460→  memoryFiles = await res.json();
   461→  renderFileList();
   462→  if (memoryFiles.length > 0) selectFile(0);
   463→}
   464→
   465→async function loadPlans() {
   466→  const res = await fetch('/api/plans');
   467→  planFiles = await res.json();
   468→  renderPlanList();
   469→}
   470→
   471→function renderFileList() {
   472→  const el = document.getElementById('file-list');
   473→  if (!memoryFiles.length) {
   474→    el.innerHTML = '<div style="padding:8px 10px;font-size:12px;color:var(--text-muted)">暂无文件</div>';
   475→    return;
   476→  }
   477→  el.innerHTML = memoryFiles.map((f, i) => `
   478→    <div class="file-item ${i === activeFile && activePlan === null ? 'active' : ''}" onclick="selectFile(${i})">
   479→      <span class="fname">📄 ${f.name}</span>
   480→      <span class="fdate">${f.updated}</span>
   481→    </div>
   482→  `).join('');
   483→}
   484→
   485→function renderPlanList() {
   486→  const el = document.getElementById('plan-list');
   487→  if (!planFiles.length) {
   488→    el.innerHTML = '<div style="padding:8px 10px;font-size:12px;color:var(--text-muted)">暂无文档</div>';
   489→    return;
   490→  }
   491→  el.innerHTML = planFiles.map((f, i) => `
   492→    <div class="file-item ${activePlan === i ? 'active' : ''}" onclick="selectPlan(${i})">
   493→      <span class="fname">📋 ${f.name}</span>
   494→      <span class="fdate">${f.updated}</span>
   495→    </div>
   496→  `).join('');
   497→}
   498→
   499→function selectFile(i) {
   500→  activeFile = i;
   501→  activePlan = null;
   502→  renderFileList();
   503→  renderPlanList();
   504→  const f = memoryFiles[i];
   505→  document.getElementById('memory-display').innerHTML = `
   506→    <h2>${f.name} <span class="badge">已更新 ${f.updated}</span></h2>
   507→    <div class="md-content">${f.html}</div>
   508→  `;
   509→}
   510→
   511→function selectPlan(i) {
   512→  activePlan = i;
   513→  activeFile = null;
   514→  renderFileList();
   515→  renderPlanList();
   516→  const f = planFiles[i];
   517→  document.getElementById('memory-display').innerHTML = `
   518→    <h2>📋 ${f.name} <span class="badge">设计文档</span> <span class="badge" style="background:#1a3a2a;color:#4ade80">${f.updated}</span></h2>
   519→    <div class="md-content">${f.html}</div>
   520→  `;
   521→}
   522→
   523→// ── History ──
   524→async function loadSessions() {
   525→  const res = await fetch('/api/sessions');
   526→  sessions = await res.json();
   527→  renderSessionList();
   528→}
   529→
   530→function renderSessionList() {
   531→  const el = document.getElementById('session-list');
   532→  if (!sessions.length) {
   533→    el.innerHTML = '<div style="padding:16px;font-size:13px;color:var(--text-muted)">暂无会话记录</div>';
   534→    return;
   535→  }
   536→  el.innerHTML = sessions.map((s, i) => `
   537→    <div class="session-item ${i === activeSession ? 'active' : ''}" onclick="selectSession(${i})">
   538→      <div class="s-date">🕐 ${s.timestamp}</div>
   539→      <div class="s-preview">${escHtml(s.first_message || '(无预览)')}</div>
   540→    </div>
   541→  `).join('');
   542→}
   543→
   544→async function selectSession(i) {
   545→  activeSession = i;
   546→  renderSessionList();
   547→  const s = sessions[i];
   548→  const view = document.getElementById('conversation-view');
   549→  view.innerHTML = '<div class="loading"><div class="spinner"></div> 加载中...</div>';
   550→
   551→  const res = await fetch('/api/conversation/' + s.id);
   552→  const rounds = await res.json();
   553→
   554→  if (!rounds.length) {
   555→    view.innerHTML = '<div class="empty-state"><div class="icon">🤷</div><p>该会话暂无可解析的对话内容</p></div>';
   556→    return;
   557→  }
   558→
   559→  view.innerHTML = rounds.map((r, idx) => `
   560→    <div class="round-card">
   561→      <div class="round-header" onclick="toggleRound(this)">
   562→        <span class="round-num">Round ${idx + 1}</span>
   563→        <span style="color:var(--text);font-size:13px">${escHtml(r.user.slice(0, 60))}${r.user.length > 60 ? '…' : ''}</span>
   564→        <span class="chevron">▾</span>
   565→      </div>
   566→      <div class="round-body">
   567→        <div class="msg-user">
   568→          <div class="msg-label"><span class="msg-dot"></span>用户</div>
   569→          <div class="msg-text">${escHtml(r.user)}</div>
   570→        </div>
   571→        <div class="msg-assistant">
   572→          <div class="msg-label"><span class="msg-dot"></span>Kiro</div>
   573→          <div class="md-content">${r.assistant_html}</div>
   574→        </div>
   575→      </div>
   576→    </div>
   577→  `).join('');
   578→}
   579→
   580→function toggleRound(header) {
   581→  header.classList.toggle('collapsed');
   582→  header.nextElementSibling.classList.toggle('hidden');
